      { id: 1006, yearNumeric: 1, yearDisplay: "1 ب.و", title: "الميثاق المنبوذ", description: "يوافق هالدريك على ميثاق دفاع مشترك مع الإلف، لكن الكاليان يقرر خيانته. يعتبر هالدريك الميثاق لاغيًا." },
      { id: 1007, yearNumeric: 1, yearDisplay: "1 ب.و", title: "عهد هالدريك الأول", description: "يبدأ عهد هالدريك الأول (الأمير هالدريك سابقًا). تنتهي نهضة ويسنوث." }
